module TopModule;  
    reg a, b;  
    wire y;  

    xnor_gate uut (  
        .a(a),  
        .b(b),  
        .y(y)  
    );  

    initial begin  
        // Test case 1: a=0, b=0, expected y=1  
        a = 0;  
        b = 0;  
        #10;  

        // Test case 2: a=0, b=1, expected y=0  
        a = 0;  
        b = 1;  
        #10;  

        // Test case 3: a=1, b=0, expected y=0  
        a = 1;  
        b = 0;  
        #10;  

        // Test case 4: a=1, b=1, expected y=1  
        a = 1;  
        b = 1;  
        #10;  

        $finish;  
    end  
endmodule

